// Lark/Telegram 消息内容提取和Challenge验证
// n8n Code节点：提取消息内容

const input = $input.first().json;

// 获取请求体（可能是body字段或直接是对象）
const body = input.body || input;

console.log('📥 收到请求，body:', JSON.stringify(body, null, 2));

// 🔐 处理Lark Challenge验证请求
if (body.type === 'url_verification' && body.challenge) {
  console.log('🔐 收到Lark Challenge验证请求，challenge:', body.challenge);

  // 返回challenge值，完成验证
  return {
    json: {
      isChallenge: true,
      challenge: body.challenge,
      type: 'url_verification',
      source: 'lark'
    }
  };
}

// 📨 判断消息来源并处理

// 检查是否是Telegram消息
if (body.update_id !== undefined || body.message) {
  // Telegram消息格式
  console.log('📱 识别为Telegram消息');

  const tgMessage = body.message || {};
  const tgFrom = tgMessage.from || {};
  const tgChat = tgMessage.chat || {};

  // 提取Telegram消息内容
  const messageText = tgMessage.text || tgMessage.caption || '';
  const messageId = tgMessage.message_id || '';
  const chatId = tgChat.id ? String(tgChat.id) : '';
  const chatTitle = tgChat.title || '';
  const senderId = tgFrom.id ? String(tgFrom.id) : '';
  const senderName = tgFrom.first_name || tgFrom.username || '未知用户';
  const senderUsername = tgFrom.username || '';
  const timestamp = tgMessage.date || Math.floor(Date.now() / 1000);

  // 格式化时间
  const messageTime = new Date(parseInt(timestamp) * 1000).toISOString();

  console.log('📱 收到Telegram消息:', {
    messageId,
    chatId,
    chatTitle,
    senderId,
    senderName,
    senderUsername,
    messageText,
    messageTime
  });

  return {
    json: {
      isChallenge: false,
      source: 'telegram',
      messageId: String(messageId),
      chatId: chatId,
      chatTitle: chatTitle,
      chatType: tgChat.type || '',
      senderId: senderId,
      senderName: senderName,
      senderUsername: senderUsername,
      messageText: messageText.trim(),
      messageTime,
      timestamp: parseInt(timestamp),
      rawEvent: body
    }
  };
}

// 📨 处理Lark消息事件
// 解析Lark Webhook事件
const event = body.event || {};
const message = event.message || {};
const sender = event.sender || {};

// 提取消息内容
let messageText = '';
if (message.message_type === 'text') {
  messageText = message.content || '';
  // 解析JSON格式的content
  try {
    const contentObj = JSON.parse(messageText);
    messageText = contentObj.text || messageText;
  } catch (e) {
    // 如果不是JSON，直接使用
  }
}

// 提取关键信息
const chatId = message.chat_id || '';
const messageId = message.message_id || '';
const senderId = sender.sender_id?.user_id || sender.sender_id || '';
const senderName = sender.sender_name || '未知用户';
const timestamp = message.create_time || Date.now();

// 格式化时间
const messageTime = new Date(parseInt(timestamp) * 1000).toISOString();

console.log('📨 收到Lark消息:', {
  messageId,
  chatId,
  senderId,
  senderName,
  messageText,
  messageTime
});

return {
  json: {
    isChallenge: false,
    source: 'lark',
    messageId,
    chatId,
    senderId,
    senderName,
    messageText: messageText.trim(),
    messageTime,
    timestamp: parseInt(timestamp),
    rawEvent: body
  }
};

// 构建Lark Challenge验证响应 / 处理正常消息并格式化数据
// n8n Code节点：构建Challenge响应

// 检查是否是正常消息事件（不是challenge验证）
const isNormalMessage = 
  $json.isChallenge === false ||  // 明确标记为非challenge
  ($json.body && $json.body.event_type) ||  // 有event_type说明是正常消息
  ($json.body && $json.body.event);  // 有event说明是正常消息

if (isNormalMessage) {
  // 处理正常消息，格式化数据供下游使用
  console.log('📨 处理正常消息，格式化数据');

  // 格式化时间：YYMMDD hhmmss
  let formattedTime = '';
  if ($json.messageTime) {
    // 如果已有messageTime（ISO格式），转换为YYMMDD hhmmss
    const date = new Date($json.messageTime);
    const year = date.getFullYear().toString().slice(-2); // 后两位年份
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    const seconds = String(date.getSeconds()).padStart(2, '0');
    formattedTime = `${year}${month}${day} ${hours}${minutes}${seconds}`;
  } else if ($json.timestamp) {
    // 如果有timestamp，转换为YYMMDD hhmmss
    const date = new Date(parseInt($json.timestamp) * 1000);
    const year = date.getFullYear().toString().slice(-2);
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    const seconds = String(date.getSeconds()).padStart(2, '0');
    formattedTime = `${year}${month}${day} ${hours}${minutes}${seconds}`;
  } else {
    // 使用当前时间
    const date = new Date();
    const year = date.getFullYear().toString().slice(-2);
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    const seconds = String(date.getSeconds()).padStart(2, '0');
    formattedTime = `${year}${month}${day} ${hours}${minutes}${seconds}`;
  }

  // 返回格式化后的数据
  return {
    json: {
      ...$json,  // 保留原有字段
      formattedTime: formattedTime,  // 添加格式化后的时间
      timeFormat: 'YYMMDD hhmmss'  // 时间格式说明
    }
  };
}

// 处理challenge验证请求
// 兼容两种数据格式：
// 1. 来自"提取消息内容"节点：{ isChallenge: true, challenge: "xxx" }
// 2. 直接来自Webhook：{ body: { challenge: "xxx", type: "url_verification" } }
const challenge = $json.challenge || $json.body?.challenge || '';

if (!challenge) {
  console.error('❌ 未找到challenge值，当前数据:', JSON.stringify($json, null, 2));
  throw new Error('未找到challenge值');
}

console.log('🔐 构建Challenge响应，challenge:', challenge);

// 返回包含challenge的JSON对象（n8n会自动序列化）
// 确保返回格式：{ challenge: "xxx" }
return {
  json: {
    challenge: challenge
  }
};

