// 解析AI识别结果
const aiResponse = $input.first().json;
const originalMessage = $node['提取消息内容'].json;

let intentResult;
try {
  // 获取AI返回的内容
  const content = aiResponse.choices?.[0]?.message?.content || aiResponse.message?.content || '';

  console.log('📥 AI原始响应:', content);

  // 尝试提取JSON数组（优先）
  let jsonMatch = content.match(/\[[\s\S]*\]/);
  if (!jsonMatch) {
    // 如果没有数组，尝试提取JSON对象
    jsonMatch = content.match(/\{[\s\S]*\}/);
  }

  if (jsonMatch) {
    const jsonStr = jsonMatch[0];
    const parsed = JSON.parse(jsonStr);

    // 如果是数组，取第一个元素
    if (Array.isArray(parsed) && parsed.length > 0) {
      intentResult = parsed[0];
    } else if (typeof parsed === 'object') {
      intentResult = parsed;
    }
  } else {
    // 如果没有JSON，尝试从文本中提取
    intentResult = {
      isQueryRequest: content.toLowerCase().includes('true') || content.toLowerCase().includes('是'),
      reason: content
    };
  }

  // 确保字段完整，使用原始消息数据填充
  intentResult = {
    isQueryRequest: String(intentResult.isQueryRequest || 'false'),
    type: intentResult.type || originalMessage.source || 'unknown',
    senderid: intentResult.senderid || (originalMessage.senderId ? parseInt(originalMessage.senderId) : 0),
    messagid: intentResult.messagid || (originalMessage.messageId ? parseInt(originalMessage.messageId) : 0),
    chatid: intentResult.chatid || originalMessage.chatId || '',
    text: intentResult.text !== undefined ? intentResult.text : originalMessage.messageText || '',
    reason: intentResult.reason || ''
  };

} catch (e) {
  console.error('❌ 解析AI响应失败:', e);
  console.error('原始内容:', content);

  // 使用原始消息数据作为fallback
  intentResult = {
    isQueryRequest: 'false',
    type: originalMessage.source || 'unknown',
    senderid: originalMessage.senderId ? parseInt(originalMessage.senderId) : 0,
    messagid: originalMessage.messageId ? parseInt(originalMessage.messageId) : 0,
    chatid: originalMessage.chatId || '',
    text: originalMessage.messageText || '',
    reason: '解析失败: ' + e.message
  };
}

console.log('🎯 意图识别结果:', intentResult);

// 返回用户需要的格式（数组格式）
return {
  json: [intentResult]
};

// 处理知识库查询结果
const kbResponse = $input.first().json;
const originalMessage = $node['解析意图识别结果'].json;

// 解析知识库返回的数据
let knowledgeBaseItems = [];
let matchedSQL = null;
let matchScore = 0;

if (kbResponse.success && kbResponse.data) {
  knowledgeBaseItems = kbResponse.data.items || kbResponse.data || [];

  // 查找最匹配的SQL（按相似度排序）
  if (knowledgeBaseItems.length > 0) {
    // 假设知识库返回的数据格式：{ query: "原始查询", sql: "SQL语句", similarity: 0.95 }
    const sortedItems = knowledgeBaseItems.sort((a, b) => (b.similarity || b.score || 0) - (a.similarity || a.score || 0));
    const bestMatch = sortedItems[0];

    // 如果相似度 > 0.8，使用匹配的SQL
    if ((bestMatch.similarity || bestMatch.score || 0) > 0.8) {
      matchedSQL = bestMatch.sql || bestMatch.query_sql || bestMatch.content;
      matchScore = bestMatch.similarity || bestMatch.score || 0;
      console.log('✅ 找到匹配的SQL:', matchedSQL);
    } else {
      console.log('⚠️ 相似度不足，需要生成新SQL');
    }
  }
}

console.log('📚 知识库查询结果:', {
  itemsCount: knowledgeBaseItems.length,
  matchedSQL: matchedSQL ? '已找到' : '未找到',
  matchScore
});

return {
  json: {
    ...originalMessage,
    knowledgeBase: {
      items: knowledgeBaseItems,
      matchedSQL,
      matchScore,
      hasMatch: !!matchedSQL
    }
  }
};

// 提取生成的SQL
const aiResponse = $input.first().json;
const originalData = $node['处理知识库结果'].json;

let generatedSQL = '';
try {
  const content = aiResponse.choices?.[0]?.message?.content || aiResponse.message?.content || '';

  // 提取SQL语句（去除markdown代码块标记）
  generatedSQL = content
    .replace(/```sql\s*/gi, '')
    .replace(/```\s*/g, '')
    .trim();

  // 如果包含SELECT，提取SELECT到分号或结尾的部分
  const selectMatch = generatedSQL.match(/(SELECT[\s\S]*?)(?:;|$)/i);
  if (selectMatch) {
    generatedSQL = selectMatch[1].trim();
  }
} catch (e) {
  console.error('提取SQL失败:', e);
  generatedSQL = '';
}

console.log('🔧 生成的SQL:', generatedSQL);

return {
  json: {
    ...originalData,
    generatedSQL,
    sqlSource: 'new'
  }
};

// 使用匹配的SQL或新生成的SQL
const data = $input.first().json;

const finalSQL = data.knowledgeBase?.matchedSQL || data.generatedSQL || '';
const sqlSource = data.knowledgeBase?.hasMatch ? 'knowledge_base' : 'new';

if (!finalSQL) {
  throw new Error('无法生成SQL语句');
}

console.log('✅ 最终使用的SQL:', finalSQL);
console.log('📝 SQL来源:', sqlSource);

return {
  json: {
    ...data,
    finalSQL,
    sqlSource
  }
};

